import React from 'react';
import { useNavigate } from 'react-router-dom';
import { IoIosArrowRoundBack } from 'react-icons/io';
import { BiPrinter } from 'react-icons/bi';
import c from './receipt.module.scss';

/* ----------------------------------------------------------
   ⬇︎ Временный инлайновый helper ― печатает ТОЛЬКО #invoicePos
   ---------------------------------------------------------- */
function printOnlyInvoice(pageSize = '90mm') {
  const selector = '#invoicePos';

  // 1) генерируем CSS для печати только выбранного блока
  const css = `
    @media print {
      @page { size: ${pageSize}; margin: 0; }

      body * {
        visibility: hidden !important;
        margin: 0;
        padding: 0;
      }

      ${selector}, ${selector} * {
        visibility: visible !important;
      }

      ${selector} {
        position: absolute;
        inset: 0;
        margin: 0 auto;
      }
    }
  `;

  // 2) добавляем <style> во <head>
  const style = document.createElement('style');
  style.setAttribute('data-temp-print', 'true');
  style.appendChild(document.createTextNode(css));
  document.head.appendChild(style);

  // 3) удаляем после завершения печати
  const cleanup = () => {
    style.parentNode?.removeChild(style);
    window.removeEventListener('afterprint', cleanup);
  };
  window.addEventListener('afterprint', cleanup);

  // 4) запускаем диалог печати
  window.print();
}

const Receipt = () => {
  const navigate = useNavigate();

  // чек в localStorage
  const sale = JSON.parse(localStorage.getItem('receipt')); // {id, total, items:[...]}

  if (!sale) return <p>Нет данных для чека</p>;

  const sum = Number(sale.total);     // общая сумма
  const vat = sum * 0.1;              // условный НДС 10 %
  const grand = sum + vat;

  return (
    /* 👇 id нужен для принтера, className — для CSS-модуля */
    <div id="invoicePos" className={c.invoicePos}>
      <h3 style={{ textAlign: 'center' }}>Чек №{sale.id}</h3>

      <div className={c.bot}>
        <table>
          <thead>
            <tr className={c.tabletitle}>
              <th><h2>Название</h2></th>
              <th><h2>Кол-во</h2></th>
              <th><h2>Сумма</h2></th>
            </tr>
          </thead>

          <tbody>
            {sale.items.map(it => (
              <tr key={it.code} className={c.service}>
                <td className={c.tableitem}>{it.name}</td>
                <td className={c.tableitem}>{it.quantity}</td>
                <td className={c.tableitem}>{Number(it.total).toFixed(2)}</td>
              </tr>
            ))}
          </tbody>

          <tfoot>
            <tr className={c.tabletitle}>
              <td></td>
              <td><h2>Всего:</h2></td>
              <td><h2>{sum.toFixed(2)} сом</h2></td>
            </tr>
            <tr>
              <td></td>
              <td>НДС (10 %)</td>
              <td>{vat.toFixed(2)}</td>
            </tr>
            <tr>
              <td></td>
              <td><strong>К оплате</strong></td>
              <td><strong>{grand.toFixed(2)}</strong></td>
            </tr>
          </tfoot>
        </table>
      </div>

      {/* Кнопки управления (не попадают в печать) */}
      <div className={c.buttons}>
        <button className={c.back} onClick={() => navigate(-1)}>
          <IoIosArrowRoundBack />
        </button>

        <button
          className={c.print}
          onClick={() => printOnlyInvoice('90mm')}
        >
          Распечатать чек <BiPrinter />
        </button>
      </div>
    </div>
  );
};

export default Receipt;
